navigator.geolocation.getCurrentPosition(async (pos) => {
  const { latitude, longitude } = pos.coords;
  const url = `https://api.open-meteo.com/v1/forecast?latitude=${latitude}&longitude=${longitude}&current=temperature_2m,apparent_temperature,weather_code,wind_speed_10m&timezone=auto`;
  const res = await fetch(url);
  const data = await res.json();
  window.__weatherResult = { latitude, longitude, data };
  return window.__weatherResult;
}, async (err) => {
  window.__weatherResult = { error: err.message };
  return window.__weatherResult;
});

const pos = await new Promise((resolve, reject) => {
  if (!navigator.geolocation) return reject(new Error('geolocation unavailable'));
  navigator.geolocation.getCurrentPosition(resolve, reject, { enableHighAccuracy: false, timeout: 10000, maximumAge: 60000 });
});
const { latitude, longitude } = pos.coords;
const res = await fetch(`https://api.open-meteo.com/v1/forecast?latitude=${latitude}&longitude=${longitude}&current=temperature_2m,weather_code,wind_speed_10m`);
const data = await res.json();
return { latitude, longitude, current: data.current };

navigator.geolocation.getCurrentPosition(async pos => {
  const { latitude, longitude } = pos.coords;
  const url = `https://api.open-meteo.com/v1/forecast?latitude=${latitude}&longitude=${longitude}&current=temperature_2m,weather_code,wind_speed_10m`;
  const res = await fetch(url);
  const data = await res.json();
  const c = data.current || {};
  const code = c.weather_code;
  const temp = c.temperature_2m;
  const wind = c.wind_speed_10m;
  const map = {0:'clear',1:'mainly clear',2:'partly cloudy',3:'overcast',45:'fog',48:'rime fog',51:'light drizzle',53:'drizzle',55:'dense drizzle',61:'light rain',63:'rain',65:'heavy rain',71:'light snow',73:'snow',75:'heavy snow',80:'rain showers',81:'showers',82:'violent showers',95:'thunderstorm'};
  const desc = map[code] || `weather code ${code}`;
  await fetch('data:text/plain,' + encodeURIComponent(JSON.stringify({temp,wind,desc,latitude,longitude}))); // no-op for async containment
}, err => {}, { timeout: 10000 });

