const pos = await new Promise((resolve,reject)=>{
  if (!navigator.geolocation) return resolve(null);
  navigator.geolocation.getCurrentPosition(
    p => resolve({lat:p.coords.latitude, lon:p.coords.longitude}),
    _ => resolve(null),
    {timeout:10000}
  );
});
if (!pos) {
  return { error: 'geolocation unavailable' };
}
const url = `https://api.open-meteo.com/v1/forecast?latitude=${pos.lat}&longitude=${pos.lon}&current=temperature_2m,weather_code,wind_speed_10m`;
const res = await fetch(url);
const data = await res.json();
return { pos, data };

const lat = 49.393813868077764;
const lon = 17.22388380435019;
const url = `https://api.open-meteo.com/v1/forecast?latitude=${lat}&longitude=${lon}&current=temperature_2m,weather_code,wind_speed_10m&temperature_unit=celsius&windspeed_unit=kmh&timezone=auto`;
fetch(url).then(async r => ({ ok: r.ok, status: r.status, text: await r.text() })).then(res => {
  let data;
  try { data = JSON.parse(res.text); } catch (e) { data = { parseError: String(e), raw: res.text }; }
  return data;
}).then(data => {
  const current = data.current || {};
  const temp = current.temperature_2m;
  const wind = current.wind_speed_10m;
  const code = current.weather_code;
  const conditions = {
    0: 'clear sky', 1: 'mainly clear', 2: 'partly cloudy', 3: 'overcast',
    45: 'fog', 48: 'depositing rime fog', 51: 'light drizzle', 53: 'moderate drizzle', 55: 'dense drizzle',
    61: 'slight rain', 63: 'moderate rain', 65: 'heavy rain', 71: 'slight snow', 73: 'moderate snow',
    75: 'heavy snow', 80: 'rain showers', 81: 'heavy rain showers', 95: 'thunderstorm'
  }[code] || `weather code ${code}`;
  const msg = (temp != null)
    ? `It’s about ${temp}°C with ${conditions}${wind != null ? `, wind ${wind} km/h` : ''}.`
    : `I couldn’t read the temperature, but the current conditions are ${conditions}.`;
  console.log(msg);
}).catch(err => console.log(`Weather fetch failed: ${err.message || String(err)}`));

