const geo = await new Promise((resolve) => {
  if (!navigator.geolocation) return resolve({ ok:false, err:'no geolocation' });
  navigator.geolocation.getCurrentPosition(
    (pos) => resolve({ ok:true, lat: pos.coords.latitude, lon: pos.coords.longitude }),
    (err) => resolve({ ok:false, err: err.message }),
    { enableHighAccuracy: true, timeout: 10000 }
  );
});

if (!geo.ok) {
  throw new Error(`Geolocation unavailable: ${geo.err}`);
}

const res = await fetch(`https://api.open-meteo.com/v1/forecast?latitude=${geo.lat}&longitude=${geo.lon}&current=temperature_2m,apparent_temperature,weather_code,wind_speed_10m&timezone=auto`);
const data = await res.json();
